import { _ as _export_sfc, o as openBlock, c as createElementBlock, ag as createStaticVNode } from "./chunks/framework.DNT4b13o.js";
const __pageData = JSON.parse('{"title":"Live Queries","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/live-queries.md","filePath":"capabilities/live-queries.md"}');
